<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    user-select: none;
  }
  h1 {
    font-size: 2rem;
    margin-bottom: 0.25rem;
    color: #00ff88;
    text-shadow: 0 0 20px rgba(0,255,136,0.3);
    letter-spacing: 0.1em;
  }
  #score {
    font-size: 1.4rem;
    margin: 0.5rem 0;
    color: #ffd700;
    text-shadow: 0 0 10px rgba(255,215,0,0.3);
    min-height: 2rem;
  }
  #board-wrapper {
    position: relative;
    border: 3px solid #00ff88;
    border-radius: 8px;
    box-shadow: 0 0 30px rgba(0,255,136,0.15), inset 0 0 30px rgba(0,0,0,0.3);
    overflow: hidden;
  }
  #snake {
    display: block;
    background: #0f0f23;
  }
  .controls {
    display: flex;
    gap: 0.75rem;
    margin-top: 1rem;
  }
  button {
    padding: 0.6rem 1.6rem;
    font-size: 1rem;
    font-weight: 600;
    border: 2px solid #00ff88;
    border-radius: 6px;
    background: transparent;
    color: #00ff88;
    cursor: pointer;
    transition: all 0.15s ease;
    letter-spacing: 0.05em;
  }
  button:hover { background: rgba(0,255,136,0.12); }
  button:active { transform: scale(0.96); }
  button.active { background: rgba(0,255,136,0.25); box-shadow: 0 0 12px rgba(0,255,136,0.3); }
  #status {
    margin-top: 0.5rem;
    font-size: 0.95rem;
    color: #888;
    min-height: 1.4rem;
  }
  .game-over-overlay {
    position: absolute;
    inset: 0;
    background: rgba(0,0,0,0.7);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    font-weight: 700;
    color: #ff4444;
    text-shadow: 0 0 20px rgba(255,68,68,0.5);
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.3s;
  }
  .game-over-overlay.visible { opacity: 1; }
</style>
</head>
<body>

<h1>🐍 SNAKE</h1>
<div id="score">Score: 0</div>
<div id="board-wrapper">
  <canvas id="snake" width="400" height="400"></canvas>
  <div class="game-over-overlay" id="overlay">GAME OVER</div>
</div>
<div class="controls">
  <button id="start">▶ Start</button>
  <button id="pause">⏸ Pause</button>
  <button id="reset">↺ Reset</button>
</div>
<div id="status">Press Start or use arrow keys</div>

<script>
(function() {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');
  const resetBtn = document.getElementById('reset');
  const overlay = document.getElementById('overlay');
  const statusEl = document.getElementById('status');

  const GRID = 20;
  const CELL = canvas.width / GRID;

  let snakeArr, dir, nextDir, food, score, alive, running, tickInterval, gameOver;

  function init() {
    const mid = Math.floor(GRID / 2);
    snakeArr = [
      [mid, mid],
      [mid - 1, mid],
      [mid - 2, mid]
    ];
    dir = 'right';
    nextDir = 'right';
    score = 0;
    alive = true;
    running = false;
    gameOver = false;
    overlay.classList.remove('visible');
    statusEl.textContent = 'Press Start or use arrow keys';
    placeFood();
    updateScore();
    draw();
  }

  function placeFood() {
    const occupied = new Set(snakeArr.map(s => s[0] + ',' + s[1]));
    let x, y;
    do {
      x = Math.floor(Math.random() * GRID);
      y = Math.floor(Math.random() * GRID);
    } while (occupied.has(x + ',' + y));
    food = [x, y];
  }

  function updateScore() {
    scoreEl.textContent = 'Score: ' + score;
  }

  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= GRID; i++) {
      ctx.beginPath();
      ctx.moveTo(i * CELL, 0);
      ctx.lineTo(i * CELL, canvas.height);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(0, i * CELL);
      ctx.lineTo(canvas.width, i * CELL);
      ctx.stroke();
    }

    // Food with glow
    const fx = food[0] * CELL + CELL / 2;
    const fy = food[1] * CELL + CELL / 2;
    const glow = ctx.createRadialGradient(fx, fy, 2, fx, fy, CELL);
    glow.addColorStop(0, 'rgba(255, 68, 68, 0.9)');
    glow.addColorStop(0.6, 'rgba(255, 68, 68, 0.3)');
    glow.addColorStop(1, 'rgba(255, 68, 68, 0)');
    ctx.fillStyle = glow;
    ctx.fillRect(food[0] * CELL - CELL / 2, food[1] * CELL - CELL / 2, CELL * 2, CELL * 2);
    ctx.fillStyle = '#ff4444';
    ctx.beginPath();
    ctx.arc(fx, fy, CELL * 0.38, 0, Math.PI * 2);
    ctx.fill();

    // Snake
    for (let i = snakeArr.length - 1; i >= 0; i--) {
      const seg = snakeArr[i];
      const x = seg[0] * CELL;
      const y = seg[1] * CELL;
      const pad = 1;

      if (i === 0) {
        // Head
        const grad = ctx.createLinearGradient(x, y, x + CELL, y + CELL);
        grad.addColorStop(0, '#00ff88');
        grad.addColorStop(1, '#00cc66');
        ctx.fillStyle = grad;
        ctx.shadowColor = '#00ff88';
        ctx.shadowBlur = 10;
        roundRect(ctx, x + pad, y + pad, CELL - pad * 2, CELL - pad * 2, 5);
        ctx.fill();
        ctx.shadowBlur = 0;

        // Eyes
        const eyeSize = CELL * 0.13;
        ctx.fillStyle = '#0f0f23';
        let ex1, ey1, ex2, ey2;
        if (dir === 'right') { ex1 = x + CELL*0.65; ey1 = y + CELL*0.28; ex2 = x + CELL*0.65; ey2 = y + CELL*0.65; }
        else if (dir === 'left') { ex1 = x + CELL*0.35; ey1 = y + CELL*0.28; ex2 = x + CELL*0.35; ey2 = y + CELL*0.65; }
        else if (dir === 'up') { ex1 = x + CELL*0.28; ey1 = y + CELL*0.35; ex2 = x + CELL*0.65; ey2 = y + CELL*0.35; }
        else { ex1 = x + CELL*0.28; ey1 = y + CELL*0.65; ex2 = x + CELL*0.65; ey2 = y + CELL*0.65; }
        ctx.beginPath(); ctx.arc(ex1, ey1, eyeSize, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(ex2, ey2, eyeSize, 0, Math.PI*2); ctx.fill();
      } else {
        // Body
        const t = i / snakeArr.length;
        const r = Math.round(0 + t * 10);
        const g = Math.round(255 - t * 120);
        const b = Math.round(136 - t * 60);
        ctx.fillStyle = `rgb(${r},${g},${b})`;
        ctx.shadowColor = `rgba(0,255,136,${0.3 - t * 0.25})`;
        ctx.shadowBlur = 6;
        roundRect(ctx, x + pad + 1, y + pad + 1, CELL - (pad + 1) * 2, CELL - (pad + 1) * 2, 4);
        ctx.fill();
        ctx.shadowBlur = 0;
      }
    }
  }

  function roundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function tick() {
    if (!alive || !running) return;

    dir = nextDir;

    const head = snakeArr[0];
    let nx = head[0], ny = head[1];
    if (dir === 'up') ny--;
    else if (dir === 'down') ny++;
    else if (dir === 'left') nx--;
    else if (dir === 'right') nx++;

    // Wall collision
    if (nx < 0 || nx >= GRID || ny < 0 || ny >= GRID) {
      alive = false;
      running = false;
      clearInterval(tickInterval);
      overlay.classList.add('visible');
      statusEl.textContent = 'Game Over! Press Reset.';
      draw();
      return;
    }

    // Self collision
    for (let i = 0; i < snakeArr.length; i++) {
      if (snakeArr[i][0] === nx && snakeArr[i][1] === ny) {
        alive = false;
        running = false;
        clearInterval(tickInterval);
        overlay.classList.add('visible');
        statusEl.textContent = 'Game Over! Press Reset.';
        draw();
        return;
      }
    }

    const newHead = [nx, ny];
    snakeArr.unshift(newHead);

    // Food collision
    if (nx === food[0] && ny === food[1]) {
      score++;
      updateScore();
      placeFood();
    } else {
      snakeArr.pop();
    }

    draw();
  }

  function startGame() {
    if (gameOver) {
      init();
    }
    if (!running) {
      running = true;
      startBtn.classList.add('active');
      startBtn.textContent = '▶ Running';
      pauseBtn.classList.remove('active');
      statusEl.textContent = 'Playing — use arrow keys';
      tickInterval = setInterval(tick, 120);
      draw();
    }
  }

  function pauseGame() {
    if (running) {
      running = false;
      clearInterval(tickInterval);
      startBtn.classList.remove('active');
      startBtn.textContent = '▶ Start';
      pauseBtn.classList.add('active');
      statusEl.textContent = 'Paused';
    }
  }

  function resetGame() {
    running = false;
    clearInterval(tickInterval);
    startBtn.classList.remove('active');
    startBtn.textContent = '▶ Start';
    pauseBtn.classList.remove('active');
    gameOver = false;
    init();
  }

  function setDirection(d) {
    const opposites = { up: 'down', down: 'up', left: 'right', right: 'left' };
    if (d !== opposites[dir]) {
      nextDir = d;
    }
  }

  // Keyboard
  document.addEventListener('keydown', function(e) {
    const keyMap = {
      ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
      w: 'up', s: 'down', a: 'left', d: 'right',
      W: 'up', S: 'down', A: 'left', D: 'right'
    };
    if (keyMap[e.key]) {
      e.preventDefault();
      setDirection(keyMap[e.key]);
      if (!running && !gameOver) startGame();
    }
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      if (!running) startGame();
      else pauseGame();
    }
  });

  startBtn.addEventListener('click', startGame);
  pauseBtn.addEventListener('click', pauseGame);
  resetBtn.addEventListener('click', resetGame);

  // Public API
  window.game = {
    get w() { return GRID; },
    get h() { return GRID; },

    reset: function() {
      running = false;
      clearInterval(tickInterval);
      startBtn.classList.remove('active');
      startBtn.textContent = '▶ Start';
      pauseBtn.classList.remove('active');
      gameOver = false;
      init();
    },

    tick: function() {
      if (!alive) return;
      if (!running) {
        running = true;
        tickInterval = setInterval(tick, 120);
      }
      tick();
    },

    setDir: function(d) {
      setDirection(d);
    },

    setFood: function(x, y) {
      food = [x, y];
      draw();
    },

    snake: function() {
      return snakeArr.map(function(s) { return [s[0], s[1]]; });
    },

    food: function() {
      return [food[0], food[1]];
    },

    alive: function() {
      return alive;
    },

    score: function() {
      return score;
    }
  };

  // Initialize
  init();
})();
</script>
</body>
</html>
